parameters.inputSchema:
{
  "type": "object",
  "properties": {
    "summary": {
      "type": "string",
      "description": "Kurze Zusammenfassung in 2 bis 3 Sätzen auf Deutsch"
    },
    "sentiment": {
      "type": "string",
      "enum": ["good", "neutral", "bad"]
    },
    "open_todo": {
      "type": "boolean",
      "description": "True, wenn ein Rückruf, eine Klärung, ein Termin oder eine andere Aktion offen ist"
    }
  },
  "required": ["summary", "sentiment", "open_todo"]
}

parameters.jsCode:
const body = $json.body;

const normalized = {
  source_channel: 'webhook',
  customer_name: body.name ?? '',
  customer_email: body.email ?? '',
  customer_phone: body.phone ?? '',
  subject: body.subject ?? '',
  text: body.message ?? ''
};

return {
  json: normalized
};

const body = $json.body;

const combinedSegments = $json.segments
  .map(segment => `Sprecher ${segment.speaker}: ${segment.text}`)
  .join(" ");

const normalized = {
  source_channel: 'audio',
  customer_name:  '',
  customer_email: '',
  customer_phone: body.phone ?? '',
  subject: '',
  text: combinedSegments ?? '',
};

return {
  json: normalized
};

const from_match = $json.from.match(/^(.+?)\s*<(.+?)>$/);

let name = "";
let email = "";

if (from_match) {
  name = from_match[1];
  email = from_match[2];
}

const normalized = {
  source_channel: 'email',
  customer_name: name ?? '',
  customer_email: email ?? '',
  customer_phone: '',
  subject: $json.subject ?? '',
  text: $json.textPlain ?? ''
};

return {
  json: normalized
};
